+    }
+
+    private static List<string> SplitIntoSentences(string text)
+    {
+        var raw = text.Split(SentenceDelimiters, StringSplitOptions.RemoveEmptyEntries);
+
+        return raw
+            .Select(s => s.Trim())
+            .Where(s => s.Length > 0)
+            .Select((s, i) =>
+            {
+                // Re-attach the original delimiter when possible.
+                int offset = raw.Take(i + 1).Sum(r => r.Length) + i;
+                char delimiter = offset < text.Length ? text[offset] : '.';
+                return s + delimiter;
+            })
+            .ToList();
+    }
+
+    private static Dictionary<string, int> BuildWordFrequencies(List<string> sentences)
+    {
+        var freq = new Dictionary<string, int>(StringComparer.OrdinalIgnoreCase);
+
+        foreach (var sentence in sentences)
+        {
+            foreach (var word in TokenizeWords(sentence))
+            {
+                if (word.Length < 3) continue; // skip very short / stop-ish words
+                freq[word] = freq.GetValueOrDefault(word) + 1;
+            }
+        }
+
+        return freq;
+    }
+
+    private static List<(string Sentence, int Index, double Score)> ScoreSentences(
+        List<string> sentences,
+        Dictionary<string, int> wordFrequencies)
+    {
+        return sentences.Select((sentence, index) =>
+        {
+            var words = TokenizeWords(sentence);
+            double score = words.Where(w => w.Length >= 3)
+                                .Sum(w => wordFrequencies.GetValueOrDefault(w));
+
+            // Normalize by word count to avoid bias toward long sentences.
+            if (words.Count > 0)
+                score /= words.Count;
+
+            return (sentence, index, score);
+        }).ToList();
+    }
+
+    private static List<string> TokenizeWords(string text)
+    {
+        return WordRegex().Matches(text)
+            .Select(m => m.Value.ToLowerInvariant())
+            .ToList();
+    }
+
+    [GeneratedRegex(@"\b\w+\b")]
+    private static partial Regex WordRegex();
+}
